        body, pos = parse(s, pos+2)
        return Lam(body), pos
    elif s[pos:pos+2] == '01':
        func, pos = parse(s, pos+2)
        arg, pos = parse(s, pos)
        return App(func, arg), pos
    else:
        # Count 1s until 0
        count = 0
        while pos < len(s) and s[pos] == '1':
            count += 1
            pos += 1
        pos += 1  # skip the '0'
        return Var(count), pos

